insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('5504c000-5011-4a00-9000-0000000000b4','5504c000-5011-4a00-9000-0000000000a1','DiGiCo SD/Quantum — tela, bancos e snapshots (front oficial)','texto','<p><strong>A DiGiCo é o padrão-ouro das grandes turnês e festivais.</strong> Se você vê um festival grande, uma turnê internacional ou um musical de teatro, muito provavelmente tem uma DiGiCo (série SD ou Quantum) na frente e no monitor. Ela é famosa por ser extremamente poderosa, centrada em <strong>tela sensível ao toque</strong>, e por um sistema de <strong>snapshots</strong> impecável para shows com muitas trocas. Nesta aula você conhece a superfície e opera o console no simulador.</p>
