insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-00000000d105','5504c000-5011-4a00-9000-0000000000c4','Para que servem os snapshots na DiGiCo?','Guardar e recuperar o estado da mesa para cada momento do show (com recall safe) — essencial em shows com muitas trocas.',5,1);
